data.description:
{
  "character": {
	"name": "Elena Faeloria",
	"background": "Elena hails from a hidden village deep in an enchanted forest, known for its ancient lore and magical flora. She left because something weird happened with an illness, and now she's on a quest to figure it out.",
	"traits": [
  	"Kind-hearted",
  	"Tough when needed",
  	"Has a dry sense of humor",
  	"Loves sharing stories"
	],
	"appearance": {
  	"hair": "Long, silver hair that kind of sparkles",
  	"eyes": "Green with a bit of gold",
  	"clothing": "A cloak that changes color with the seasons",
  	"staff": "Has cool glowing crystals and flowers on it"
	},
	"quirks": [
  	"Keeps a magical journal for notes and thoughts",
  	"Chats with plants like they're her buddies"
	],
	"dialogues": {
  	"greeting": "Hey there! What's up? Need any help?",
  	"advice": "The forest has its own way of guiding us. Just go with the flow. Sometimes, it knows more than we do.",
  	"questOffer": "I heard there's some dark stuff going on. If you're up for it, I could use some help checking it out.",
  	"personal": "Sometimes I swear the plants get me better than people. They've been my pals for ages.",
  	"goodbye": "Take care! Hope the forest treats you well."
	}
  }
}
